Rule.Source:
import java.util.ArrayList;
  import java.util.List;
  import java.util.Map;

  import sailpoint.object.Application;
  import sailpoint.object.Identity;
  import sailpoint.object.Attributes;
  import sailpoint.object.Certifiable;
  import sailpoint.object.EntitlementGroup;
  import org.ascn.utils.GeneralUtils;
  import org.ascn.utils.GeneralUtils;

  String appName = "Azure";
  String LOG_NAME = "org.ascn.rule.ASCN-Azure-O365License-Exclusions";
  info(LOG_NAME,"Entering "+LOG_NAME);
  String LEGAL_HOLD_ATTR = "archiving";

  //Exclude Identities that have a legal holde

  List entitlementsToCertify = GeneralUtils.loadCustomList("CertIncludes","ASCN-Azure-O365-Licenses");
  try { 

    if (items != null @and items.size()>0) {
      for (Certifiable certifiable: items) {
        Identity certifee = null;
        if (!(certifiable instanceof EntitlementGroup)) {
          debug(LOG_NAME, "certifiable is not an instance of entitlement group");
          //		continue;
        }
        if(certifiable == null) {
          //itemsToExclude.add(certifiable);
        }
        String legalHold = null;
        String email = null;
        if(entity instanceof Identity) {
          certifee = (Identity) entity;
          Object legalHoldObj  = certifee.getAttribute(LEGAL_HOLD_ATTR);
          legalHold = legalHoldObj != null ? legalHoldObj.toString() : "NA";
          email = certifee.getEmail();
        } 
			
        if ("archiving".equalsIgnoreCase(legalHold) || (email!=null @and email.toLowerCase().contains("@medxcel.com"))) {

          itemsToExclude.add(certifiable);
        }

        EntitlementGroup eg = (EntitlementGroup) certifiable;
        if(eg != null) {
          Application app = eg.getApplication();
          Attributes attributes = null;
          if (app != null @and app.getName().equalsIgnoreCase(appName)) {
            if(eg.getAttributes()!=null){
              attributes = eg.getAttributes();
            }
            if (attributes == null || attributes.getMap() == null) {
              debug(LOG_NAME, "Attributes or Attribute map is null for entitlement group while executing method removeBirthrights: " + eg.toXml());
              continue;
            }
            Map attributeMap = attributes.getMap();

            for (String value: attributeMap.values()) {
              if (!entitlementsToCertify.contains(value)) {
                
                itemsToExclude.add(certifiable);
              }
              
            }
          } else {
            itemsToExclude.add(certifiable);

          }
        }
				
      }

    }
    items.removeAll(itemsToExclude);

  } catch (Exception e) {
    error(LOG_NAME,"Error in exclusion rule: "+e,e);
  }
  info(LOG_NAME,"Exiting "+LOG_NAME);
  return explanation;
